import numpy as np
import procfunc as pf
from procfunc.nodes import types as t

from infinigen_v2.generators.shaders.util.coord import coord_warp


@pf.nodes.node_function
def fractal_crack(
    vector: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    w: t.SocketOrVal[float] = 0.0,
    spread_x: t.SocketOrVal[float] = 0.08,
    spread_y: t.SocketOrVal[float] = 1.0,
    spread_multiplier: t.SocketOrVal[float] = 1.0,
    size: t.SocketOrVal[float] = 0.0,
    detail: t.SocketOrVal[float] = 0.0,
    lacunarity: t.SocketOrVal[float] = 0.0,
) -> pf.ProcNode[float]:
    # Code generated by procfunc v0.3.0

    value_factor_9 = pf.nodes.math.clamp(detail - 4.0)
    value_factor_8 = pf.nodes.math.clamp(detail - 3.0)
    value_factor_7 = pf.nodes.math.clamp(detail - 2.0)
    value_factor_6 = pf.nodes.math.clamp(detail - 1.0)
    value_factor_5 = pf.nodes.math.clamp(detail + 0.0)
    value_factor_4 = 1.0 / lacunarity
    value_factor_3 = (value_factor_5 * value_factor_4) / lacunarity
    value_factor_2 = (value_factor_6 * value_factor_3) / lacunarity
    value_factor_1 = (value_factor_7 * value_factor_2) / lacunarity
    value_factor = (value_factor_8 * value_factor_1) / lacunarity
    value_scale_4 = 1.0 / size
    value_21 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w,
        scale=value_scale_4,
        voronoi_dimensions="4D",
    )
    value_w_4 = 10.0 * size
    value_20 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w + value_w_4,
        scale=value_scale_4 * lacunarity,
        voronoi_dimensions="4D",
    )
    value_19 = pf.nodes.math.minimum(a=value_21, b=value_20)
    value_18 = pf.nodes.func.mix(factor=value_21, a=value_19, b=value_21)
    value_17 = pf.nodes.func.mix(
        factor=value_factor_5 * value_factor_4,
        a=value_21,
        b=value_18,
    )
    value_w_3 = 20.0 * size
    value_scale_3 = lacunarity**2.0
    value_16 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w + value_w_3,
        scale=value_scale_4 * value_scale_3,
        voronoi_dimensions="4D",
    )
    value_15 = pf.nodes.math.minimum(a=value_17, b=value_16)
    value_14 = pf.nodes.func.mix(factor=value_17, a=value_15, b=value_17)
    value_13 = pf.nodes.func.mix(
        factor=value_factor_6 * value_factor_3,
        a=value_17,
        b=value_14,
    )
    value_w_2 = 30.0 * size
    value_scale_2 = value_scale_3 * lacunarity
    value_12 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w + value_w_2,
        scale=value_scale_4 * value_scale_2,
        voronoi_dimensions="4D",
    )
    value_11 = pf.nodes.math.minimum(a=value_13, b=value_12)
    value_10 = pf.nodes.func.mix(factor=value_13, a=value_11, b=value_13)
    value_9 = pf.nodes.func.mix(
        factor=value_factor_7 * value_factor_2,
        a=value_13,
        b=value_10,
    )
    value_w_1 = 40.0 * size
    value_scale_1 = value_scale_2 * lacunarity
    value_8 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w + value_w_1,
        scale=value_scale_4 * value_scale_1,
        voronoi_dimensions="4D",
    )
    value_7 = pf.nodes.math.minimum(a=value_9, b=value_8)
    value_6 = pf.nodes.func.mix(factor=value_9, a=value_7, b=value_9)
    value_5 = pf.nodes.func.mix(
        factor=value_factor_8 * value_factor_1,
        a=value_9,
        b=value_6,
    )
    value_w = 50.0 * size
    value_scale = value_scale_1 * lacunarity
    value_4 = pf.nodes.shader.voronoi_distance(
        vector=vector,
        w=w + value_w,
        scale=value_scale_4 * value_scale,
        voronoi_dimensions="4D",
    )
    value_3 = pf.nodes.math.minimum(a=value_5, b=value_4)
    value_2 = pf.nodes.func.mix(factor=value_5, a=value_3, b=value_5)
    value_1 = pf.nodes.func.mix(
        factor=value_factor_9 * value_factor,
        a=value_5,
        b=value_2,
    )
    value_value = pf.nodes.shader.noise(vector=vector, scale=1.0 / size, detail=4.0)
    value = pf.nodes.func.map_range(value=value_value.fac, from_min=0.2, from_max=0.8)
    from_min = pf.nodes.func.map_range(value=spread_y, from_min=0.5, to_max=0.999)
    from_max_1 = pf.nodes.func.map_range(value=spread_y, from_max=0.5, to_min=0.0001)
    from_max_factor = pf.nodes.func.map_range(
        value=value,
        from_min=from_min,
        from_max=from_max_1,
    )
    from_max = pf.nodes.func.mix(factor=from_max_factor, a=spread_x, b=0.0)

    map_range = pf.nodes.func.map_range(
        value=value_1 / 0.5,
        from_max=from_max * spread_multiplier,
        to_min=1.0,
        to_max=0.0,
    )
    return map_range


@pf.nodes.node_function
def cracks_mask(
    vector: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    displacement_a: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    displacement_b: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    height_threshold: t.SocketOrVal[float] = 0.0,
    blend_distance: t.SocketOrVal[float] = 0.01,
    random_seed: t.SocketOrVal[float] = 0.0,
    warp_size: t.SocketOrVal[float] = 0.05,
    warp_strength: t.SocketOrVal[float] = 1.3,
    warp_detail: t.SocketOrVal[float] = 4.0,
    group_size: t.SocketOrVal[float] = 1.0,
    group_detail: t.SocketOrVal[float] = 4.0,
    group_spread: t.SocketOrVal[float] = 1.0,
    crack_spread_x: t.SocketOrVal[float] = 0.142,
    crack_spread_y: t.SocketOrVal[float] = 0.2841,
    crack_size: t.SocketOrVal[float] = 0.1,
    crack_detail: t.SocketOrVal[float] = 3.0,
    hole_spread: t.SocketOrVal[float] = 0.5,
    hole_size: t.SocketOrVal[float] = 0.1,
    hole_detail: t.SocketOrVal[float] = 4.0,
) -> pf.ProcNode[float]:
    # Code generated by procfunc v0.3.0

    coord_warp_result = coord_warp(
        vector=vector,
        size=warp_size,
        strength=warp_strength,
        detail=warp_detail,
        phase=random_seed,
    )

    w = random_seed - 50.0

    coord_warp_result_1 = coord_warp(
        vector=vector,
        size=warp_size,
        strength=warp_strength,
        detail=warp_detail,
        phase=w,
    )

    spread_multiplier_value_2 = pf.nodes.shader.voronoi(
        vector=coord_warp_result_1.vector,
        w=w + 100.0,
        scale=1.0 / group_size,
        detail=group_detail,
        lacunarity=1.5,
        normalize=True,
        voronoi_dimensions="4D",
    )
    spread_multiplier_4 = pf.nodes.func.map_range(
        value=spread_multiplier_value_2.distance,
        from_min=0.12,
        from_max=0.63,
    )
    spread_multiplier_3 = pf.nodes.func.map_range(
        value=group_spread, from_min=0.5, to_max=0.999
    )
    spread_multiplier_2 = pf.nodes.func.map_range(
        value=group_spread, from_max=0.5, to_min=0.0001
    )
    factor_1 = pf.nodes.shader.geometry()
    factor = pf.nodes.math.vector_dot_product(
        a=factor_1.normal,
        b=displacement_a + displacement_b,
    )
    spread_multiplier_value_1 = pf.nodes.math.vector_length(
        displacement_a + displacement_b
    )
    spread_multiplier_value = pf.nodes.func.mix(
        factor=factor > 0.0,
        a=spread_multiplier_value_1 * -1.0,
        b=spread_multiplier_value_1,
    )
    spread_multiplier_from_min = blend_distance / 2.0
    spread_multiplier_1 = pf.nodes.func.map_range(
        value=spread_multiplier_value,
        from_min=height_threshold - spread_multiplier_from_min,
        from_max=height_threshold + spread_multiplier_from_min,
    )
    spread_multiplier = pf.nodes.func.map_range(
        value=spread_multiplier_4,
        from_min=spread_multiplier_3,
        from_max=spread_multiplier_2,
        to_min=spread_multiplier_1,
        to_max=0.0,
    )

    fractal_crack_result = fractal_crack(
        vector=coord_warp_result.vector,
        w=random_seed,
        spread_x=crack_spread_x,
        spread_y=crack_spread_y,
        spread_multiplier=spread_multiplier,
        size=crack_size,
        detail=crack_detail,
        lacunarity=1.618,
    )

    coord_warp_result_2 = coord_warp(
        vector=vector,
        size=warp_size,
        strength=warp_strength,
        detail=warp_detail,
        phase=random_seed + 100.0,
    )

    value = pf.nodes.shader.voronoi(
        vector=coord_warp_result_2.vector,
        w=random_seed + 35.0,
        scale=1.0 / hole_size,
        detail=hole_detail,
        lacunarity=1.5,
        normalize=True,
        voronoi_dimensions="4D",
    )
    from_max_2 = hole_spread * 0.46
    from_max_1 = pf.nodes.func.float_curve(
        value=spread_multiplier,
        curve=np.array([[0.0, 0.0], [0.3364, 0.7563], [1.0, 1.0]]),
    )
    from_max = from_max_1 * spread_multiplier_1
    result_1 = pf.nodes.func.map_range(
        value=value.distance,
        from_max=from_max_2 * from_max,
        to_min=1.0,
        to_max=0.0,
    )
    result = pf.nodes.math.maximum(a=fractal_crack_result, b=result_1)

    less_than = result < 0.001
    return less_than


def cracks_dense(
    vector: pf.ProcNode[pf.Vector],
    displacement_a: pf.ProcNode[pf.Vector] | None = None,
    displacement_b: pf.ProcNode[pf.Vector] | None = None,
) -> pf.ProcNode[float]:
    # Code generated by procfunc v0.1.0

    return cracks_mask(
        vector=vector,
        displacement_a=displacement_a,
        displacement_b=displacement_b,
        height_threshold=-1.0,
        blend_distance=0.001,
        warp_size=0.03,
        warp_strength=4.0,
        warp_detail=6.0,
        group_size=0.2,
        crack_spread_x=0.1078,
        crack_spread_y=0.7886,
        crack_size=0.06,
        crack_detail=6.0,
        hole_spread=0.0,
        hole_size=0.05,
    )


def cracks_worn(
    vector: pf.ProcNode[pf.Vector],
    displacement_a: pf.ProcNode[pf.Vector] | None = None,
    displacement_b: pf.ProcNode[pf.Vector] | None = None,
) -> pf.ProcNode[float]:
    return cracks_mask(
        vector=vector,
        displacement_a=displacement_a,
        displacement_b=displacement_b,
        blend_distance=0.001,
        warp_size=0.03,
        warp_strength=2.0,
        warp_detail=6.0,
        group_size=0.3,
        group_spread=0.2256,
        crack_spread_x=0.2008,
        crack_spread_y=0.4211,
        hole_spread=0.6574,
        hole_size=0.03,
    )


def cracks_flakes(
    vector: pf.ProcNode[pf.Vector],
    displacement_a: pf.ProcNode[pf.Vector] | None = None,
    displacement_b: pf.ProcNode[pf.Vector] | None = None,
) -> pf.ProcNode[float]:
    return cracks_mask(
        vector=displacement_a,
        displacement_b=displacement_b,
        height_threshold=0,
        blend_distance=0.001,
        warp_strength=2.0,
        warp_detail=6.0,
        group_size=0.2,
        crack_spread_x=0.0605,
        crack_spread_y=0.3188,
        crack_size=0.06,
        crack_detail=6.0,
        hole_spread=0.5907,
        hole_detail=6.0,
    )


def cracks_presets(
    rng: pf.RNG,
    vector: t.SocketOrVal[pf.Vector],
) -> pf.ProcNode[float]:
    func = pf.control.choice(
        rng,
        [
            (cracks_dense, 1.0),
            (cracks_worn, 1.0),
            (cracks_flakes, 1.0),
        ],
    )
    return func(vector=vector)


def cracks_distribution(
    rng: pf.RNG,
    vector: t.SocketOrVal[pf.Vector],
    displacement_a: t.SocketOrVal[pf.Vector] | None = None,
    displacement_b: t.SocketOrVal[pf.Vector] | None = None,
    height_threshold: t.SocketOrVal[float] = -1.0,
) -> pf.ProcNode[float]:
    # Code generated by procfunc v0.3.0

    """
    Args
    ---
    height_threshold: float - if specified, cracks will only occur for areas with greater displacement than this threshold
        e.g. bricks use this to only have wear/tear on the raised parts
    """

    blend_distance = 0.001
    random_seed = 0.0

    warp_size = 2 * pf.random.uniform(rng, 0.03, 0.05)
    crack_size = 2 * pf.random.uniform(rng, 0.06, 0.1)
    group_size = 2 * pf.random.uniform(rng, 0.2, 0.3)
    hole_size = 2 * pf.random.uniform(rng, 0.03, 0.1)

    warp_strength = pf.random.uniform(rng, 1.3, 4.0)
    warp_detail = pf.random.uniform(rng, 4, 6)
    group_detail = 4.0
    group_spread = pf.random.uniform(rng, 0.2256, 1.0)
    crack_spread_x = pf.random.uniform(rng, 0.0605, 0.2008)
    crack_spread_y = pf.random.uniform(rng, 0.3188, 0.7886)
    crack_detail = pf.random.uniform(rng, 3, 6)
    hole_spread = pf.random.uniform(rng, 0.0, 0.6574)
    hole_detail = pf.random.uniform(rng, 4, 6)

    cracks_mask_result = cracks_mask(
        vector=vector,
        displacement_a=displacement_a,
        displacement_b=displacement_b,
        height_threshold=height_threshold,
        blend_distance=blend_distance,
        random_seed=random_seed,
        warp_size=warp_size,
        warp_strength=warp_strength,
        warp_detail=warp_detail,
        group_size=group_size,
        group_detail=group_detail,
        group_spread=group_spread,
        crack_spread_x=crack_spread_x,
        crack_spread_y=crack_spread_y,
        crack_size=crack_size,
        crack_detail=crack_detail,
        hole_spread=hole_spread,
        hole_size=hole_size,
        hole_detail=hole_detail,
    )
    return cracks_mask_result
